// frontend/src/components/admin/VoucherManagement.js
import React, { useState, useEffect } from 'react';
import api from '../../services/api';
import './Admin.css';

const VoucherManagement = () => {
    const [vouchers, setVouchers] = useState([]);
    const [templates, setTemplates] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [activeTab, setActiveTab] = useState('vouchers');
    const [showTemplateModal, setShowTemplateModal] = useState(false);
    const [editingTemplate, setEditingTemplate] = useState(null);
    const [actionLoading, setActionLoading] = useState(false);
    const [formData, setFormData] = useState({
        name: '',
        description: '',
        face_value: '',
        selling_price: '',
        validity_days: 365
    });

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [vouchersRes, templatesRes] = await Promise.all([
                api.get('/admin/vouchers'),
                api.get('/admin/voucher-templates')
            ]);

            if (vouchersRes.data.success) setVouchers(vouchersRes.data.data);
            if (templatesRes.data.success) setTemplates(templatesRes.data.data);
        } catch (error) {
            console.error('Error loading voucher data:', error);
            setError('Failed to load data');
        } finally {
            setLoading(false);
        }
    };

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setFormData({
            ...formData,
            [name]: name.includes('price') || name.includes('value') || name === 'validity_days' 
                ? parseFloat(value) || 0 
                : value
        });
    };

    const handleSubmitTemplate = async (e) => {
        e.preventDefault();
        setActionLoading(true);
        try {
            if (editingTemplate) {
                await api.put(`/admin/voucher-templates/${editingTemplate.id}`, formData);
            } else {
                await api.post('/admin/voucher-templates', formData);
            }
            loadData();
            setShowTemplateModal(false);
            resetForm();
        } catch (error) {
            console.error('Error saving template:', error);
            alert('Failed to save template');
        } finally {
            setActionLoading(false);
        }
    };

    const handleDeleteTemplate = async (templateId) => {
        if (!window.confirm('Are you sure you want to delete this template?')) return;

        setActionLoading(true);
        try {
            await api.delete(`/admin/voucher-templates/${templateId}`);
            loadData();
        } catch (error) {
            console.error('Error deleting template:', error);
            alert('Failed to delete template');
        } finally {
            setActionLoading(false);
        }
    };

    const resetForm = () => {
        setFormData({
            name: '',
            description: '',
            face_value: '',
            selling_price: '',
            validity_days: 365
        });
        setEditingTemplate(null);
    };

    const getStatusBadge = (status) => {
        switch(status) {
            case 'active': return <span className="badge active">Active</span>;
            case 'used': return <span className="badge used">Used</span>;
            case 'expired': return <span className="badge expired">Expired</span>;
            default: return <span className="badge">{status}</span>;
        }
    };

    if (loading) {
        return <div className="loading-spinner">Loading voucher data...</div>;
    }

    return (
        <div className="management-tab">
            <div className="management-header">
                <h1>🎫 Voucher Management</h1>
                <button className="btn-refresh" onClick={loadData}>
                    🔄 Refresh
                </button>
            </div>

            {error && <div className="error-message">{error}</div>}

            <div className="tab-navigation">
                <button 
                    className={activeTab === 'vouchers' ? 'active' : ''}
                    onClick={() => setActiveTab('vouchers')}
                >
                    All Vouchers ({vouchers.length})
                </button>
                <button 
                    className={activeTab === 'templates' ? 'active' : ''}
                    onClick={() => setActiveTab('templates')}
                >
                    Templates ({templates.length})
                </button>
            </div>

            {activeTab === 'vouchers' && (
                <div className="table-container">
                    <table className="data-table">
                        <thead>
                            <tr>
                                <th>ID</th>
                                <th>Code</th>
                                <th>Owner</th>
                                <th>Face Value</th>
                                <th>Balance</th>
                                <th>Status</th>
                                <th>Expires</th>
                                <th>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {vouchers.length === 0 ? (
                                <tr>
                                    <td colSpan="8" className="no-data">No vouchers found</td>
                                </tr>
                            ) : (
                                vouchers.map(voucher => (
                                    <tr key={voucher.id}>
                                        <td>{voucher.id}</td>
                                        <td><code>{voucher.voucher_code}</code></td>
                                        <td>{voucher.owner_name || 'Unknown'}</td>
                                        <td>R{voucher.face_value}</td>
                                        <td>R{voucher.current_balance}</td>
                                        <td>{getStatusBadge(voucher.status)}</td>
                                        <td>{new Date(voucher.expires_at).toLocaleDateString()}</td>
                                        <td>
                                            <button 
                                                className="btn-action"
                                                onClick={() => alert('View voucher details')}
                                            >
                                                View
                                            </button>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            )}

            {activeTab === 'templates' && (
                <div>
                    <div className="action-bar">
                        <button 
                            className="btn-create"
                            onClick={() => {
                                resetForm();
                                setShowTemplateModal(true);
                            }}
                        >
                            + Create New Template
                        </button>
                    </div>

                    <div className="templates-grid">
                        {templates.length === 0 ? (
                            <div className="no-data">No templates found</div>
                        ) : (
                            templates.map(template => (
                                <div key={template.id} className="template-card">
                                    <div className="template-header">
                                        <h3>{template.name}</h3>
                                        <span className={`status ${template.is_active ? 'active' : 'inactive'}`}>
                                            {template.is_active ? 'Active' : 'Inactive'}
                                        </span>
                                    </div>
                                    <p className="template-description">{template.description}</p>
                                    <div className="template-details">
                                        <div className="detail">
                                            <span>Face Value:</span>
                                            <strong>R{template.face_value}</strong>
                                        </div>
                                        <div className="detail">
                                            <span>Selling Price:</span>
                                            <strong>R{template.selling_price}</strong>
                                        </div>
                                        <div className="detail">
                                            <span>Profit:</span>
                                            <strong className="profit">
                                                R{template.face_value - template.selling_price}
                                            </strong>
                                        </div>
                                        <div className="detail">
                                            <span>Valid for:</span>
                                            <strong>{template.validity_days} days</strong>
                                        </div>
                                    </div>
                                    <div className="template-actions">
                                        <button 
                                            className="btn-edit"
                                            onClick={() => {
                                                setEditingTemplate(template);
                                                setFormData({
                                                    name: template.name,
                                                    description: template.description,
                                                    face_value: template.face_value,
                                                    selling_price: template.selling_price,
                                                    validity_days: template.validity_days
                                                });
                                                setShowTemplateModal(true);
                                            }}
                                        >
                                            ✎ Edit
                                        </button>
                                        <button 
                                            className="btn-delete-small"
                                            onClick={() => handleDeleteTemplate(template.id)}
                                            disabled={actionLoading}
                                        >
                                            🗑️ Delete
                                        </button>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                </div>
            )}

            {showTemplateModal && (
                <div className="modal-overlay" onClick={() => setShowTemplateModal(false)}>
                    <div className="modal-content" onClick={e => e.stopPropagation()}>
                        <div className="modal-header">
                            <h2>{editingTemplate ? 'Edit Template' : 'Create New Template'}</h2>
                            <button className="modal-close" onClick={() => setShowTemplateModal(false)}>×</button>
                        </div>

                        <form onSubmit={handleSubmitTemplate} className="modal-form">
                            <div className="form-group">
                                <label>Template Name *</label>
                                <input
                                    type="text"
                                    name="name"
                                    value={formData.name}
                                    onChange={handleInputChange}
                                    required
                                />
                            </div>

                            <div className="form-group">
                                <label>Description</label>
                                <textarea
                                    name="description"
                                    value={formData.description}
                                    onChange={handleInputChange}
                                    rows="3"
                                />
                            </div>

                            <div className="form-row">
                                <div className="form-group">
                                    <label>Face Value (R) *</label>
                                    <input
                                        type="number"
                                        name="face_value"
                                        value={formData.face_value}
                                        onChange={handleInputChange}
                                        min="0"
                                        step="50"
                                        required
                                    />
                                </div>

                                <div className="form-group">
                                    <label>Selling Price (R) *</label>
                                    <input
                                        type="number"
                                        name="selling_price"
                                        value={formData.selling_price}
                                        onChange={handleInputChange}
                                        min="0"
                                        step="50"
                                        required
                                    />
                                </div>
                            </div>

                            <div className="form-group">
                                <label>Validity (days) *</label>
                                <input
                                    type="number"
                                    name="validity_days"
                                    value={formData.validity_days}
                                    onChange={handleInputChange}
                                    min="1"
                                    max="730"
                                    required
                                />
                            </div>

                            <div className="modal-actions">
                                <button 
                                    type="button" 
                                    className="btn-cancel"
                                    onClick={() => setShowTemplateModal(false)}
                                >
                                    Cancel
                                </button>
                                <button 
                                    type="submit" 
                                    className="btn-save"
                                    disabled={actionLoading}
                                >
                                    {actionLoading ? 'Saving...' : (editingTemplate ? 'Update Template' : 'Create Template')}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
};

export default VoucherManagement;
